3_real_world_example.code:
console.log('1. Script start');

// Goes to standard Task Queue (Macrotask)
setTimeout(() => {
  console.log('4. setTimeout');
}, 0);

// Goes to VIP Microtask Queue
Promise.resolve().then(() => {
  console.log('3. Promise');
});

console.log('2. Script end');

// Output:
// 1. Script start
// 2. Script end
// 3. Promise      ← VIP line goes first!
// 4. setTimeout   ← Standard line goes after VIP is empty

